public void testRewritePrototypeMethodsWithNestedThis() throws Exception {
  enableTypeCheck(CheckLevel.ERROR);
  test("function Foo() {}\n" +
       "Foo.prototype.bar = function() {\n" +
       "  var nested = function() { return this.x; };\n" +
       "  return nested();\n" +
       "};",
       "function Foo() {}\n" +
       "function Foo$prototype$bar() {\n" +
       "  var nested = function() { return this.x; };\n" +
       "  return nested();\n" +
       "}");
}

public void testPrototypePropertyDefinition() throws Exception {
  testTypes(
      "/** @constructor */ function Foo() {}" +
      "/** @type {number} */ Foo.prototype.x = 5;" +
      "var f = new Foo();" +
      "var y = f.x;");
}
